#define BIGRND 0x7fffffff
#define ETA 0.3f
#define MOMENTUM 0.3f
#define WIDTH 16
#define HEIGHT 16
#define BLOCK_SIZE 16

#define ABS(x) ((x) > 0.0f ? (x) : -(x))

float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}

__kernel void bpnn_layerforward_ocl(__global float *l1,
                                    __global float *l2,
                                    __global float *conn,
                                    __global float *partial_sum,
                                    __local float *local_conn,
                                    __local float *local_l1,
                                    int n1,
                                    int n2) {
    int j = get_global_id(1);
    int k_idx = get_global_id(0);
    int local_id = get_local_id(0);
    int local_size = get_local_size(0);

    if (j > n2 || j == 0) return;

    float sum = 0.0f;

    int rows = n1 + 1;
    int cols = n2 + 1;

    for (int block = 0; block < (rows + local_size - 1) / local_size; block++) {
        int k = block * local_size + local_id;
        if (k <= n1) {
            local_l1[local_id] = l1[k];
            for (int col = 0; col <= n2; col++) {
                local_conn[local_id * (n2 + 1) + col] = conn[k * cols + col];
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        if (k <= n1) {
            sum += local_l1[local_id] * local_conn[local_id * (n2 + 1) + j];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    partial_sum[j * (get_global_size(1)) + get_global_id(1)] = sum;
}

__kernel void bpnn_adjust_weights_ocl(__global float *delta,
                                      int ndelta,
                                      __global float *ly,
                                      int nly,
                                      __global float *w,
                                      __global float *oldw) {
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j > ndelta || j == 0) return;
    if (k > nly) return;

    float new_dw = (ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k * (ndelta + 1) + j]);
    w[k * (ndelta + 1) + j] += new_dw;
    oldw[k * (ndelta + 1) + j] = new_dw;
}
